"""Lightweight request-contract helpers for inspect_repo."""

from __future__ import annotations


VALID_MODES = {"auto", "evidence", "answer"}

def test_prepare_prefetched_state_uses_broker_repository_fingerprint_hint(self):
    with tempfile.TemporaryDirectory() as tmp:
        repo_root = Path(tmp)
        (repo_root / "service.py").write_text("def handler():\n    return 'ok'\n", encoding="utf-8")
        discovered = [
            {
                "id": "input_0",
                "type": "repo",
                "classification": "internal",
                "path": repo_root,
            }
        ]
        with mock.patch.object(
            inspection_hotpath,
            "repository_fingerprint",
            side_effect=AssertionError("repository_fingerprint should not run when broker hint is present"),
        ):
            state = inspection_hotpath.prepare_prefetched_state(
                discovered,
                "trace handler",
                mode="answer",
                constraints={},
                task_params={
                    "_broker_repository_state_fingerprint": "git:test-fingerprint",
                    "_broker_repository_state_fingerprint_source": "request_cache",
                },
                execution_plan={},
                output_dir=repo_root / "out",
            )
    self.assertEqual(state["repository_state_fingerprint"], "git:test-fingerprint")
    self.assertEqual(
        state["fingerprint_state"],
        [
            {
                "kind": "broker_hint",
                "source": "request_cache",
                "fingerprint": "git:test-fingerprint",
            }
        ],
    )

func TestDecodeInspectRepoRejectsBrokerReservedRoutingParameters(t *testing.T) {
	spec, _ := FindSpec("inspect_repo")
	for _, key := range []string{
		"gpu_services",
		"gpu_service_registry_path",
		"gpu_service_health_interval_seconds",
		"service_endpoints",
		"index_cache_dir",
		"repo_inspection_cache_path",
	} {
		raw := json.RawMessage(`{"query":"trace MCP routing","input_refs":[{"type":"repo","uri":"file:///tmp/repo"}],"task_params":{"` + key + `":"caller-controlled"}}`)
		if _, err := DecodeSubmitRequest(raw, spec); err == nil {
			t.Fatalf("expected reserved task parameter %q to fail", key)
		}
	}
}
